numbers = [1, 2, 2, 3, 3, 3]
unique = set(numbers)
print(unique)  # {1, 2, 3}

# Set operations
set_a = {1, 2, 3}
set_b = {3, 4, 5}
print(set_a & set_b)  # {3}  (intersection)
print(set_a | set_b)  # {1, 2, 3, 4, 5}  (union)

try:
    number = int(input("Enter a number: "))
    result = 10 / number
    print(f"Result: {result}")
except ValueError:
    print("That's not a valid number!")
except ZeroDivisionError:
    print("Can't divide by zero!")

class Student:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def introduce(self):
        return f"Hi, I'm {self.name} and I'm {self.age}"

# Create an object (instance)
alice = Student("Alice", 15)
print(alice.introduce())  # Hi, I'm Alice and I'm 15

class Dog:
    species = "Canine"  # Class attribute (shared by all)

    def __init__(self, name):
        self.name = name  # Instance attribute (unique per dog)

    def bark(self):
        return f"{self.name} says Woof!"

buddy = Dog("Buddy")
print(buddy.bark())  # Buddy says Woof!
print(buddy.species)  # Canine
